\begin{aligned}
a_{\max } & =\frac{2}{3\left(1+\frac{4 \pi^2}{36}\right)}=\frac{2 \times 12}{36+4 \pi^2} \\\\
& =\frac{6}{9+\pi^2} \\\\
\therefore \bar{a} & =\frac{6}{9+\pi^2}
\end{aligned}
$$
